// Parsear correos de WeTransfer y extraer TODOS los archivos
// Subject: "RESILIENCIA FC 4.pdf enviado correctamente a sublimarte..."
// El body tiene una lista de archivos en texto plano

const items = [];

for (const item of $input.all()) {
  const subject = item.json.Subject || item.json.subject || '';
  const gmailId = item.json.id || '';

  if (!gmailId) continue;

  // Determinar tipo por el subject
  let tipo = null;
  if (/enviado correctamente/i.test(subject)) tipo = 'enviado';
  if (/se ha descargado/i.test(subject)) tipo = 'descargado';
  if (!tipo) continue;

  // Extraer archivos del subject primero (siempre viene 1)
  const todosArchivos = [];

  const matchEnviado = subject.match(/^(.+\.pdf)\s+enviado correctamente/i);
  if (matchEnviado) todosArchivos.push(matchEnviado[1].trim());

  const matchDescargado = subject.match(/se ha descargado\s+(.+\.pdf)$/i);
  if (matchDescargado) todosArchivos.push(matchDescargado[1].trim());

  // Buscar archivos adicionales en el texto plano del body
  // WeTransfer lista los archivos en texto plano como "NOMBRE.pdf\n100 MB"
  const texto = item.json.text || '';
  if (texto) {
    const lineas = texto.split(/\n/);
    for (const linea of lineas) {
      const l = linea.trim();
      // Solo líneas que terminen en .pdf y sean nombres cortos (sin URLs ni frases largas)
      if (/\.pdf$/i.test(l) && l.length < 150 && !l.includes('http') && !l.includes('@')) {
        if (!todosArchivos.some(a => a.toLowerCase() === l.toLowerCase())) {
          todosArchivos.push(l);
        }
      }
    }
  }

  // Registrar cada archivo como item separado
  for (const archivo of todosArchivos) {
    const equipo = archivo.replace(/\.pdf$/i, '');
    const itemGmailId = `${gmailId}_${archivo.toLowerCase().replace(/\s+/g, '_')}`;
    items.push({ json: { tipo, archivo, equipo, gmailId: itemGmailId } });
  }
}

if (items.length === 0) return [{ json: { _skip: true } }];
return items;
